    <line x1="20" y1="172" x2="680" y2="172" stroke="#27272a" stroke-width="1"/>
    <text x="20" y="196" fill="#a1a1aa" font-size="13" font-weight="700">Avoirs en bitcoin — inchangés sur les deux semaines</text>
    <rect x="20" y="209" width="660" height="40" rx="8" fill="#18181b" stroke="#3f3f46" stroke-width="1.3"/>
